import React, { useEffect, useRef, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getChannel } from '../services/api';
import videojs from 'video.js';
import 'video.js/dist/video-js.css';

const ChannelPlayer = () => {
  const { id } = useParams();
  const videoRef = useRef(null);
  const playerRef = useRef(null);
  const [channel, setChannel] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    loadChannel();
    return () => {
      if (playerRef.current) {
        playerRef.current.dispose();
        playerRef.current = null;
      }
    };
  }, [id]);

  const loadChannel = async () => {
    try {
      setLoading(true);
      const channelData = await getChannel(id);
      setChannel(channelData);

      if (channelData.stream_url) {
        // Cargar video después de que el componente se monte completamente
        setTimeout(() => {
          loadVideo(channelData.stream_url);
        }, 1000);
      }
    } catch (error) {
      console.error('Error cargando canal:', error);
      setError('Canal no encontrado');
    } finally {
      setLoading(false);
    }
  };

  const loadVideo = (streamUrl) => {
    console.log('📺 Cargando canal:', streamUrl);

    if (playerRef.current) {
      playerRef.current.dispose();
      playerRef.current = null;
    }

    setTimeout(() => {
      if (videoRef.current) {
        // Usar proxy para evitar CORS
        const proxyUrl = `http://localhost:5000/api/channels/proxy?url=${encodeURIComponent(streamUrl)}`;
        const finalUrl = streamUrl.includes('.m3u8') ? proxyUrl : streamUrl;
        const videoType = streamUrl.includes('.m3u8') ? 'application/x-mpegURL' : 'video/mp4';

        playerRef.current = videojs(videoRef.current, {
          controls: true,
          responsive: true,
          fluid: true,
          autoplay: true,
          preload: 'auto',
          liveui: true,
          html5: {
            vhs: {
              overrideNative: true,
              withCredentials: false,
              handleManifestRedirects: true
            }
          },
          sources: [{ src: finalUrl, type: videoType }]
        });

        playerRef.current.on('error', () => {
          // Si falla el proxy, intentar directo
          console.log('Proxy falló, intentando directo...');
          playerRef.current.src([{ src: streamUrl, type: videoType }]);
          playerRef.current.play();
        });
      }
    }, 500);
  };

  if (loading) return <div className="p-4 text-white">Cargando canal...</div>;
  if (error) return (
    <div className="p-4 text-white">
      <div className="text-red-400 mb-4">{error}</div>
      <Link to="/channels" className="bg-red-600 hover:bg-red-700 px-4 py-2 rounded">
        Volver a Canales
      </Link>
    </div>
  );
  if (!channel) return <div className="p-4 text-white">Canal no encontrado</div>;

  return (
    <div className="bg-black min-h-screen">
      {/* Header */}
      <div className="p-4 bg-gray-900 flex items-center justify-between">
        <div className="flex items-center space-x-4">
          {channel.logo && (
            <img
              src={channel.logo}
              alt={channel.name}
              className="w-12 h-12 object-contain bg-white rounded"
              onError={(e) => e.target.style.display = 'none'}
            />
          )}
          <div>
            <h1 className="text-white text-2xl font-bold">{channel.name}</h1>
            <p className="text-gray-400">
              {channel.country} • {channel.category}
            </p>
          </div>
        </div>

        <div className="flex space-x-2">
          <Link
            to="/channels"
            className="bg-gray-700 hover:bg-gray-600 px-4 py-2 rounded text-white"
          >
            Todos los Canales
          </Link>
          <button
            onClick={() => window.open(channel.stream_url, '_blank')}
            className="bg-blue-600 hover:bg-blue-700 px-4 py-2 rounded text-white"
          >
            Abrir Directo
          </button>
        </div>
      </div>

      {/* Video Player */}
      <div className="px-4 pb-4">
        <video
          ref={videoRef}
          className="video-js vjs-default-skin w-full"
          controls
          preload="auto"
          data-setup="{}"
          crossOrigin="anonymous"
        />
      </div>

      {/* Info del Canal */}
      <div className="px-4 py-2 bg-gray-900">
        <div className="text-sm text-gray-400">
          <span className="inline-block bg-red-600 text-white px-2 py-1 rounded text-xs mr-2">
            EN VIVO
          </span>
          Stream URL: {channel.stream_url}
        </div>
      </div>
    </div>
  );
};

export default ChannelPlayer;
